// Helper to get market data for a career by matching the career name
export function getCareerMarketData(careerName: string): MarketInfo[] | null {
  const normalizedName = careerName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
  
  // Direct match
  if (careerMarketData[normalizedName]) {
    return careerMarketData[normalizedName];
  }
  
  // Try to find a partial match
  const keys = Object.keys(careerMarketData);
  for (const key of keys) {
    if (normalizedName.includes(key) || key.includes(normalizedName)) {
      return careerMarketData[key];
    }
  }
  
  // Keyword matching - comprehensive
  const keywords: Record<string, string[]> = {
    "software-developer": ["developer", "software", "programmer", "coder", "coding", "web developer", "full stack"],
    "data-scientist": ["data science", "machine learning", "ml"],
    "data-science": ["data scientist", "data analytics"],
    "ux-designer": ["ux", "ui", "user experience", "user interface", "interaction design"],
    "product-manager": ["product management", "pm"],
    "consultant": ["consulting", "advisor", "management consulting"],
    "financial-analyst": ["financial analysis", "investment analyst", "equity analyst"],
    "economist": ["economic"],
    "doctor": ["physician", "medical doctor", "mbbs", "md"],
    "medicine": ["doctor", "physician", "healthcare", "medical"],
    "nurse": ["registered nurse", "rn"],
    "nursing": ["nurse", "nursing care", "patient care"],
    "psychology": ["psychologist", "mental health", "counselor", "therapist"],
    "psychologist": ["psychology", "counselling"],
    "lawyer": ["attorney", "advocate", "barrister", "solicitor"],
    "law": ["legal", "lawyer", "llb", "jurisprudence"],
    "accountant": ["audit", "cpa", "acca", "chartered accountant"],
    "manager": ["general manager", "operations manager"],
    "entrepreneur": ["founder", "startup", "business owner", "entrepreneurship"],
    "engineer": ["engineering general"],
    "electrical-engineering": ["electrical engineer", "electronics engineer", "power systems", "electrical"],
    "mechanical-engineering": ["mechanical engineer", "mechatronics"],
    "civil-engineering": ["civil engineer", "structural engineer", "construction engineering"],
    "computer-science": ["computer scientist", "cs degree", "software engineering"],
    "architecture": ["architect", "building design", "architectural"],
    "teacher": ["teaching", "educator", "instructor", "school teacher"],
    "education": ["teacher", "teaching", "educator"],
    "professor": ["faculty", "lecturer", "academia"],
    "journalist": ["journalism", "reporter", "news reporter"],
    "researcher": ["research scientist"],
    "scientist": ["lab", "laboratory", "scientific"],
    "graphic-designer": ["graphic design", "visual design", "illustration"],
    "content-creator": ["influencer", "blogger", "youtuber", "content creation"],
    "marketing": ["marketing manager", "brand manager", "digital marketing"],
    "marketing-director": ["cmo", "chief marketing", "vp marketing"],
    "hr-specialist": ["human resources specialist", "talent acquisition"],
    "human-resources": ["hr manager", "hr director", "people operations"],
    "policy-analyst": ["public policy", "policy research"],
    "diplomat": ["diplomacy", "foreign service", "embassy"],
    "international-relations": ["diplomat", "foreign affairs", "global affairs"],
    "chemistry": ["chemist", "chemical"],
    "physics": ["physicist", "physical sciences"],
    "biology": ["biologist", "biological", "life sciences", "biotechnology"],
    "pharmacy": ["pharmacist", "pharmaceutical"],
    "dentistry": ["dentist", "dental", "orthodontist"],
    "business-administration": ["business admin", "bba", "mba"],
    "finance": ["financial services", "investment banking", "portfolio"],
    "environmental-science": ["environmental scientist", "ecology", "climate"],
    "physical-therapy": ["physiotherapy", "physiotherapist", "pt"],
    "aerospace-engineering": ["aerospace engineer", "aeronautics", "astronautics"],
    "social-work": ["social worker", "case manager", "community work"],
    "veterinary-medicine": ["veterinarian", "vet", "animal doctor"],
    "film-production": ["filmmaker", "film director", "cinematography", "tv production"],
    "public-health": ["epidemiologist", "health policy", "population health"],
    "urban-planning": ["urban planner", "city planning", "town planning"],
    "actuarial-science": ["actuary", "risk analyst", "insurance analyst"],
    "biomedical-engineering": ["biomedical engineer", "medical devices", "bme"],
    "culinary-arts": ["chef", "culinary", "cooking", "pastry"],
    "information-technology": ["it manager", "network admin", "systems admin"],
    "sports-management": ["sports agent", "athletic director", "sports marketing"],
    "music": ["musician", "composer", "music producer", "performer"],
    "political-science": ["political analyst", "politics", "government affairs"],
    "philosophy": ["philosopher", "ethics"],
    "anthropology": ["anthropologist", "ethnography", "cultural studies"],
    "kinesiology": ["kinesiologist", "movement science", "exercise science", "human movement"],
    "genetic-counseling": ["genetic counselor", "genetics", "genomics", "hereditary"],
  };
  
  for (const [key, words] of Object.entries(keywords)) {
    for (const word of words) {
      if (normalizedName.includes(word.replace(/\s+/g, '-')) || normalizedName.includes(word.replace(/\s+/g, ''))) {
        if (careerMarketData[key]) {
          return careerMarketData[key];
        }
      }
    }
  }
  
  // Last resort: check if any word in the career name matches a key
  const careerWords = normalizedName.split('-');
  for (const word of careerWords) {
    if (word.length > 3) {
      for (const key of keys) {
        if (key.includes(word) || word.includes(key.replace(/-/g, ''))) {
          return careerMarketData[key];
        }
      }
    }
  }
  
  return null;
}
